sys_script_include.script:
var AN_BenchmarkEngine = Class.create();

AN_BenchmarkEngine.prototype = {

    evaluate: function(scanId) {

        var scorecard =
            new GlideRecord(
                'x_1920012_apprai_0_an_scorecard'
            );

        scorecard.addQuery(
            'scan',
            scanId
        );

        scorecard.query();

        if (!scorecard.next())
            return;

        this.compare(
            scanId,
            'security',
            parseInt(scorecard.security_score, 10)
        );

        this.compare(
            scanId,
            'performance',
            parseInt(scorecard.performance_score, 10)
        );

        this.compare(
            scanId,
            'quality',
            parseInt(scorecard.quality_score, 10)
        );

        this.compare(
            scanId,
            'maintainability',
            parseInt(scorecard.maintainability_score, 10)
        );

        this.compare(
            scanId,
            'update_set',
            parseInt(scorecard.update_set_score, 10)
        );
    },

    compare: function(
        scanId,
        dimension,
        score
    ) {

        var bench =
            new GlideRecord(
                'x_1920012_apprai_0_an_benchmark'
            );

        bench.addQuery(
            'dimension',
            dimension
        );

        bench.query();

        if (!bench.next())
            return;

        var top =
            parseInt(
                bench.top_quartile,
                10
            );

        var avg =
            parseInt(
                bench.community_average,
                10
            );

        var bottom =
            parseInt(
                bench.bottom_quartile,
                10
            );

        var finding =
            new GlideRecord(
                'x_1920012_apprai_0_an_finding'
            );

        if (score >= top) {

            finding.initialize();

            finding.scan = scanId;
            finding.dimension = dimension;
            finding.severity = 'low';
            finding.title =
                'Top Quartile Performance';

            finding.description =
                dimension +
                ' score (' +
                score +
                ') is above industry top quartile (' +
                top +
                ').';

            finding.insert();

        } else if (score < avg) {

            finding.initialize();

            finding.scan = scanId;
            finding.dimension = dimension;
            finding.severity = 'medium';
            finding.title =
                'Below Community Average';

            finding.description =
                dimension +
                ' score (' +
                score +
                ') is below community average (' +
                avg +
                ').';

            finding.insert();
        }
    },

    type: 'AN_BenchmarkEngine'
};
